// ── Pillar mapping ──────────────────────────────────────
const PILLAR_MAP = {
  'Cybersecurity':           'prevent',
  'AI & Surveillance':       'prevent',
  'Defence & Security':      'protect',
  'Physical Security':       'protect',
  'Dual-use Technology':     'prepare',
  'Drones & Unmanned Systems':'prepare',
  'Space & Satellite':       'prepare',
  'Critical Infrastructure': 'respond',
  'Maritime & Aerospace':    'respond',
  'Energy & Grid Resilience':'recover',
};

const PILLAR_COLORS = {
  prevent: '#2196F3',
  protect: '#FF6B35',
  prepare: '#9C27B0',
  respond: '#FF9800',
  recover: '#4CAF50',
};

const PILLAR_LABELS = {
  prevent: 'Prevent',
  protect: 'Protect',
  prepare: 'Prepare',
  respond: 'Respond',
  recover: 'Recover',
};

const PILLAR_ORDER = ['prevent', 'protect', 'prepare', 'respond', 'recover'];

function getPillar(sectorNormalized) {
  return PILLAR_MAP[sectorNormalized] || 'respond';
}

function getPillarColor(pillar) {
  return PILLAR_COLORS[pillar] || '#607D8B';
}

// Enrich each company with pillar
COMPANIES.forEach(c => {
  c.pillar = getPillar(c.sector_normalized);
});

// ── Sector configuration ───────────────────────────────────
const SECTOR_COLORS = {
  'Defence & Security':      '#FF6B35',
  'Cybersecurity':           '#2196F3',
  'Energy & Grid Resilience':'#4CAF50',
  'Critical Infrastructure': '#FF9800',
  'Maritime & Aerospace':    '#00BCD4',
  'Dual-use Technology':     '#9C27B0',
  'Physical Security':       '#E91E63',
  'AI & Surveillance':       '#00E5FF',
  'Space & Satellite':       '#7C4DFF',
  'Drones & Unmanned Systems':'#CDDC39',
};

function getSectorColor(sector) {
  return SECTOR_COLORS[sector] || '#607D8B';
}

