const CURRENT_LANG = { lang: 'en' };

// ── Country helpers ────────────────────────────────────────
function countryFlag(cc) {
  if (!cc || cc.length !== 2) return '🌍';
  const offset = 127397;
  return String.fromCodePoint(...cc.toUpperCase().split('').map(c => c.charCodeAt(0) + offset));
}

function getCountryName(company, lang) {
  if (lang === 'fr') return company.country_name_fr || company.country_name_en;
  if (lang === 'local') return company.country_name_local || company.country_name_en;
  return company.country_name_en;
}

function getDescription(company, lang) {
  if (lang === 'fr') return company.description_fr || company.description_en || company.description_local || '';
  if (lang === 'local') return company.description_local || company.description_en || '';
  return company.description_en || company.description_local || '';
}

// ── Apply i18n to DOM ──────────────────────────────────────
function applyLanguage(lang) {
  const uiLang = lang === 'local' ? 'en' : lang;
  const strings = UI[uiLang] || UI.en;
  CURRENT_LANG.lang = lang;

  document.querySelectorAll('[data-i18n]').forEach(el => {
    const key = el.dataset.i18n;
    if (strings[key] !== undefined) {
      let text = strings[key];
      if (key === 'heroSubtitle') {
        const countries = new Set(COMPANIES.map(c => c.country)).size;
        text = text.replace('{total}', COMPANIES.length).replace('{countries}', countries);
      }
      el.textContent = text;
    }
  });

  rebuildSectorFilter(lang);
  rebuildCountryFilter(lang);
  renderCards(getFiltered());
  updateMap(getFiltered());
}

// ── Pillar counts ──────────────────────────────────────────
function getPillarCounts() {
  const counts = {};
  PILLAR_ORDER.forEach(p => counts[p] = 0);
  COMPANIES.forEach(c => { counts[c.pillar] = (counts[c.pillar] || 0) + 1; });
  return counts;
}

// ── Build sector dropdown ──────────────────────────────────
function rebuildSectorFilter(lang) {
  const sel = document.getElementById('sectorFilter');
  if (!sel) return;
  const uiLang = lang === 'local' ? 'en' : lang;
  const current = sel.value;
  sel.innerHTML = '';
  const allOpt = document.createElement('option');
  allOpt.value = '';
  allOpt.textContent = (UI[uiLang] || UI.en).allSectors;
  sel.appendChild(allOpt);
  const sectors = [...new Set(COMPANIES.map(c => c.sector_normalized).filter(Boolean))].sort();
  sectors.forEach(s => {
    const opt = document.createElement('option');
    opt.value = s;
    opt.textContent = s;
    sel.appendChild(opt);
  });
  sel.value = current;
}

// ── Build country dropdown ─────────────────────────────────
function rebuildCountryFilter(lang) {
  const sel = document.getElementById('countryFilter');
  if (!sel) return;
  const uiLang = lang === 'local' ? 'en' : lang;
  const current = sel.value;
  sel.innerHTML = '';
  const allOpt = document.createElement('option');
  allOpt.value = '';
  allOpt.textContent = (UI[uiLang] || UI.en).allCountries;
  sel.appendChild(allOpt);

  const countryMap = {};
  COMPANIES.forEach(c => {
    if (!countryMap[c.country]) {
      countryMap[c.country] = getCountryName(c, lang);
    }
  });

  Object.entries(countryMap)
    .sort((a, b) => a[1].localeCompare(b[1]))
    .forEach(([cc, name]) => {
      const opt = document.createElement('option');
      opt.value = cc;
      opt.textContent = `${countryFlag(cc)} ${name}`;
      sel.appendChild(opt);
    });
  sel.value = current;
}

// ── Filter state ───────────────────────────────────────────
let filterSearch = '';
let filterPillar = '';
let filterSector = '';
let filterCountry = '';
let sortMode = 'az';

function getFiltered() {
  let list = COMPANIES.filter(c => {
    const nameMatch = !filterSearch || c.name.toLowerCase().includes(filterSearch.toLowerCase());
    const pillarMatch = !filterPillar || c.pillar === filterPillar;
    const sectorMatch = !filterSector || c.sector_normalized === filterSector;
    const countryMatch = !filterCountry || c.country === filterCountry;
    return nameMatch && pillarMatch && sectorMatch && countryMatch;
  });

  if (sortMode === 'az') {
    list.sort((a, b) => a.name.localeCompare(b.name));
  } else if (sortMode === 'pillar') {
    list.sort((a, b) => PILLAR_ORDER.indexOf(a.pillar) - PILLAR_ORDER.indexOf(b.pillar) || a.name.localeCompare(b.name));
  } else if (sortMode === 'country') {
    list.sort((a, b) => a.country.localeCompare(b.country) || a.name.localeCompare(b.name));
  } else if (sortMode === 'sector') {
    list.sort((a, b) => (a.sector_normalized || '').localeCompare(b.sector_normalized || '') || a.name.localeCompare(b.name));
  }

  return list;
}

function updateFilterCount(filtered) {
  const vis = document.getElementById('visibleCount');
  if (vis) vis.textContent = filtered.length;
  const total = document.getElementById('totalCount');
  if (total) total.textContent = COMPANIES.length;
  const mapVis = document.getElementById('mapVisibleCount');
  if (mapVis) mapVis.textContent = filtered.length;
}

// ── Leaflet Map ────────────────────────────────────────────
let leafletMap = null;
let markerCluster = null;
let allMarkers = [];

const COUNTRY_CENTERS = {
  NL: [52.1, 5.3], BE: [50.5, 4.5], DE: [51.2, 10.5], DK: [56.0, 10.0],
  EE: [59.4, 24.7], ES: [40.4, -3.7], FI: [64.0, 26.0], FR: [46.2, 2.2],
  IT: [42.8, 12.8], LT: [55.2, 24.0], LV: [56.9, 24.6], NO: [60.5, 8.5],
  PL: [52.0, 19.0], SE: [60.1, 18.6], UK: [51.5, -0.1],
};

function initMap() {
  if (leafletMap) return;

  leafletMap = L.map('leaflet-map', {
    center: [54, 10],
    zoom: 4,
    zoomControl: true,
    attributionControl: true,
  });

  L.tileLayer('https://{s}.basemaps.cartocdn.com/dark_all/{z}/{x}/{y}{r}.png', {
    attribution: '&copy; <a href="https://www.openstreetmap.org/copyright">OpenStreetMap</a> contributors &copy; <a href="https://carto.com/attributions">CARTO</a>',
    subdomains: 'abcd',
    maxZoom: 19,
  }).addTo(leafletMap);

  markerCluster = L.markerClusterGroup({
    showCoverageOnHover: false,
    maxClusterRadius: 50,
    iconCreateFunction: function(cluster) {
      const count = cluster.getChildCount();
      const size = count < 10 ? 'small' : count < 50 ? 'medium' : 'large';
      return L.divIcon({
        html: `<div><span>${count}</span></div>`,
        className: `marker-cluster marker-cluster-${size}`,
        iconSize: L.point(40, 40),
      });
    }
  });

  COMPANIES.forEach(company => {
    let lat = company.lat;
    let lon = company.lon;
    if (!lat || !lon || (lat === 0 && lon === 0)) {
      const cc = COUNTRY_CENTERS[company.country];
      if (cc) { lat = cc[0]; lon = cc[1]; }
      else return;
    }

    const color = getPillarColor(company.pillar);
    const marker = L.circleMarker([lat, lon], {
      radius: 7,
      fillColor: color,
      color: 'rgba(255,255,255,0.3)',
      weight: 1,
      opacity: 1,
      fillOpacity: 0.85,
    });

    marker.bindPopup(() => buildPopupHtml(company), { maxWidth: 300, minWidth: 240 });
    allMarkers.push({ company, marker });
    markerCluster.addLayer(marker);
  });

  leafletMap.addLayer(markerCluster);
  buildMapLegend();
}

function buildPopupHtml(company) {
  const lang = CURRENT_LANG.lang;
  const pillarColor = getPillarColor(company.pillar);
  const sectorColor = getSectorColor(company.sector_normalized);
  const desc = getDescription(company, lang);
  const flag = countryFlag(company.country);
  const uiLang = lang === 'local' ? 'en' : lang;
  const visitText = (UI[uiLang] || UI.en).visitWebsite;
  const pillarLabel = PILLAR_LABELS[company.pillar] || company.pillar;

  return `
    <div>
      <div class="popup-name">${escHtml(company.name)}</div>
      <span class="popup-pillar" style="background:${pillarColor}">${escHtml(pillarLabel)}</span>
      <span class="popup-sector" style="background:${sectorColor}">${escHtml(company.sector_normalized || company.sector || '')}</span>
      <div class="popup-location">${flag} ${escHtml(company.city || '')}${company.city && company.country ? ', ' : ''}${escHtml(getCountryName(company, lang))}</div>
      ${desc ? `<div class="popup-desc">${escHtml(desc)}</div>` : ''}
      ${company.website ? `<a class="popup-link" href="${escHtml(company.website)}" target="_blank" rel="noopener noreferrer">↗ ${visitText}</a>` : ''}
    </div>
  `;
}

function escHtml(str) {
  if (!str) return '';
  return str.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');
}

function updateMap(filtered) {
  if (!leafletMap) return;
  const filteredSet = new Set(filtered.map(c => c.name));

  markerCluster.clearLayers();
  allMarkers.forEach(({ company, marker }) => {
    if (filteredSet.has(company.name)) {
      markerCluster.addLayer(marker);
    }
  });
}

function buildMapLegend() {
  const legend = document.getElementById('mapLegend');
  if (!legend) return;
  legend.innerHTML = `<div class="legend-title">Pillar</div>`;
  PILLAR_ORDER.forEach(pillar => {
    const color = PILLAR_COLORS[pillar];
    const label = PILLAR_LABELS[pillar];
    const div = document.createElement('div');
    div.className = 'legend-item';
    div.innerHTML = `<div class="legend-dot" style="background:${color}"></div><span>${label}</span>`;
    legend.appendChild(div);
  });
}

// ── Company Cards ──────────────────────────────────────────
function renderCards(companies) {
  const grid = document.getElementById('companyGrid');
  const noRes = document.getElementById('noResults');
  if (!grid) return;

  const lang = CURRENT_LANG.lang;
  const uiLang = lang === 'local' ? 'en' : lang;
  const visitText = (UI[uiLang] || UI.en).visitWebsite;

  if (companies.length === 0) {
    grid.innerHTML = '';
    if (noRes) noRes.classList.remove('hidden');
    return;
  }
  if (noRes) noRes.classList.add('hidden');

  grid.innerHTML = companies.map((c, i) => {
    const pillarColor = getPillarColor(c.pillar);
    const sectorColor = getSectorColor(c.sector_normalized);
    const desc = getDescription(c, lang);
    const flag = countryFlag(c.country);
    const countryName = getCountryName(c, lang);
    const animDelay = Math.min(i * 0.02, 0.5);
    const pillarLabel = PILLAR_LABELS[c.pillar] || c.pillar;

    return `
      <div class="company-card" style="--card-delay:${animDelay}s; animation-delay:${animDelay}s; border-top: 3px solid ${pillarColor};">
        <div class="card-header">
          <div class="card-name">${escHtml(c.name)}</div>
          <div class="card-badges">
            <span class="card-pillar-badge" style="background:${pillarColor}">${escHtml(pillarLabel)}</span>
            <span class="card-sector-badge" style="background:${sectorColor}">${escHtml(c.sector_normalized || c.sector || '')}</span>
          </div>
        </div>
        <div class="card-location">
          <span class="flag">${flag}</span>
          <span>${escHtml(c.city || '')}${c.city ? ', ' : ''}${escHtml(countryName)}</span>
        </div>
        ${desc ? `<div class="card-desc">${escHtml(desc)}</div>` : ''}
        <div class="card-footer">
          ${c.website ? `<a class="card-link" href="${escHtml(c.website)}" target="_blank" rel="noopener noreferrer">${escHtml(c.website.replace(/^https?:\/\/(www\.)?/,'').replace(/\/$/,''))}</a>` : ''}
        </div>
      </div>
    `;
  }).join('');
}

// ── Hero countries strip ───────────────────────────────────
function buildHeroCountries() {
  const el = document.getElementById('heroCountries');
  if (!el) return;
  const countMap = {};
  COMPANIES.forEach(c => { countMap[c.country] = (countMap[c.country] || 0) + 1; });
  const sorted = Object.entries(countMap).sort((a,b) => b[1]-a[1]);
  el.innerHTML = sorted.map(([cc, cnt]) => `
    <div class="country-pill">
      <span class="flag">${countryFlag(cc)}</span>
      <span class="count">${cnt}</span>
    </div>
  `).join('');
}

// ── Footer flags ───────────────────────────────────────────
function buildFooterFlags() {
  const el = document.getElementById('footerFlags');
  if (!el) return;
  const countries = [...new Set(COMPANIES.map(c => c.country))].sort();
  el.innerHTML = countries.map(cc => `<span title="${cc}">${countryFlag(cc)}</span>`).join('');
}

// ── Charts ─────────────────────────────────────────────────
let chartPillarInstance = null;
let chartCountryInstance = null;
let chartSectorInstance = null;

function buildCharts() {
  // Pillar distribution
  const pillarCounts = getPillarCounts();
  const pLabels = PILLAR_ORDER.map(p => PILLAR_LABELS[p]);
  const pValues = PILLAR_ORDER.map(p => pillarCounts[p]);
  const pColors = PILLAR_ORDER.map(p => PILLAR_COLORS[p]);

  const ctxP = document.getElementById('chartPillar');
  if (ctxP) {
    if (chartPillarInstance) chartPillarInstance.destroy();
    chartPillarInstance = new Chart(ctxP, {
      type: 'bar',
      data: {
        labels: pLabels,
        datasets: [{
          data: pValues,
          backgroundColor: pColors.map(c => c + 'CC'),
          borderColor: pColors,
          borderWidth: 1,
          borderRadius: 4,
        }]
      },
      options: {
        responsive: true,
        maintainAspectRatio: false,
        plugins: {
          legend: { display: false },
          tooltip: {
            backgroundColor: '#0F2035',
            borderColor: '#1E3550',
            borderWidth: 1,
            titleColor: '#E8F0F8',
            bodyColor: '#8BA5C0',
            titleFont: { family: "'IBM Plex Mono'" },
            bodyFont: { family: "'IBM Plex Sans'" },
            callbacks: {
              label: (ctx) => ` ${ctx.parsed.y} organisations`
            }
          }
        },
        scales: {
          x: {
            ticks: { color: '#E8F0F8', font: { family: "'IBM Plex Mono'", size: 12, weight: 600 } },
            grid: { display: false },
          },
          y: {
            ticks: { color: '#8BA5C0', font: { family: "'IBM Plex Mono'", size: 11 } },
            grid: { color: 'rgba(30,53,80,0.6)' },
          }
        }
      }
    });
  }

  // Country distribution
  const countMap = {};
  const countryNameMap = {};
  COMPANIES.forEach(c => {
    countMap[c.country] = (countMap[c.country] || 0) + 1;
    countryNameMap[c.country] = c.country_name_en;
  });
  const sorted = Object.entries(countMap).sort((a,b) => b[1]-a[1]);
  const labels = sorted.map(([cc]) => `${countryFlag(cc)} ${countryNameMap[cc]}`);
  const values = sorted.map(([,v]) => v);

  const ctxC = document.getElementById('chartCountry');
  if (ctxC) {
    if (chartCountryInstance) chartCountryInstance.destroy();
    chartCountryInstance = new Chart(ctxC, {
      type: 'bar',
      data: {
        labels,
        datasets: [{
          data: values,
          backgroundColor: values.map((_, i) => `hsla(${200 + i * 12}, 60%, 55%, 0.8)`),
          borderColor: 'transparent',
          borderRadius: 3,
        }]
      },
      options: {
        indexAxis: 'y',
        responsive: true,
        maintainAspectRatio: false,
        plugins: {
          legend: { display: false },
          tooltip: {
            backgroundColor: '#0F2035',
            borderColor: '#1E3550',
            borderWidth: 1,
            titleColor: '#E8F0F8',
            bodyColor: '#8BA5C0',
            titleFont: { family: "'IBM Plex Mono'" },
            bodyFont: { family: "'IBM Plex Sans'" },
          }
        },
        scales: {
          x: {
            ticks: { color: '#8BA5C0', font: { family: "'IBM Plex Mono'", size: 11 } },
            grid: { color: 'rgba(30,53,80,0.6)' },
          },
          y: {
            ticks: { color: '#E8F0F8', font: { family: "'IBM Plex Sans'", size: 12 } },
            grid: { display: false },
          }
        }
      }
    });
  }

  // Sector per pillar (doughnut showing sectors)
  const sectorMap = {};
  COMPANIES.forEach(c => {
    const s = c.sector_normalized || 'Other';
    sectorMap[s] = (sectorMap[s] || 0) + 1;
  });
  const sectorSorted = Object.entries(sectorMap).sort((a,b) => b[1]-a[1]);
  const sLabels = sectorSorted.map(([s]) => s);
  const sValues = sectorSorted.map(([,v]) => v);
  const sColors = sLabels.map(s => getSectorColor(s));

  const ctxS = document.getElementById('chartSector');
  if (ctxS) {
    if (chartSectorInstance) chartSectorInstance.destroy();
    chartSectorInstance = new Chart(ctxS, {
      type: 'doughnut',
      data: {
        labels: sLabels,
        datasets: [{
          data: sValues,
          backgroundColor: sColors.map(c => c + 'CC'),
          borderColor: '#0D1B2A',
          borderWidth: 2,
          hoverOffset: 8,
        }]
      },
      options: {
        responsive: true,
        maintainAspectRatio: false,
        cutout: '62%',
        plugins: {
          legend: {
            position: 'right',
            labels: {
              color: '#8BA5C0',
              font: { family: "'IBM Plex Sans'", size: 11 },
              padding: 12,
              boxWidth: 12,
              boxHeight: 12,
            }
          },
          tooltip: {
            backgroundColor: '#0F2035',
            borderColor: '#1E3550',
            borderWidth: 1,
            titleColor: '#E8F0F8',
            bodyColor: '#8BA5C0',
            titleFont: { family: "'IBM Plex Mono'" },
            callbacks: {
              label: (ctx) => ` ${ctx.parsed} organisations (${((ctx.parsed/COMPANIES.length)*100).toFixed(1)}%)`
            }
          }
        }
      }
    });
  }
}

// ── Navbar scroll effect ───────────────────────────────────
function initNavScroll() {
  const nav = document.getElementById('navbar');
  window.addEventListener('scroll', () => {
    if (window.scrollY > 20) nav.classList.add('scrolled');
    else nav.classList.remove('scrolled');
  }, { passive: true });
}

// ── Main init ──────────────────────────────────────────────
function init() {
  const countries = new Set(COMPANIES.map(c => c.country)).size;

  // Hero subtitle
  const heroSub = document.getElementById('heroSubtitle');
  if (heroSub) {
    heroSub.textContent = UI.en.heroSubtitle
      .replace('{total}', COMPANIES.length)
      .replace('{countries}', countries);
  }

  // Pillar counts
  const counts = getPillarCounts();
  PILLAR_ORDER.forEach(p => {
    const heroEl = document.getElementById(`hero${p.charAt(0).toUpperCase() + p.slice(1)}Count`);
    if (heroEl) heroEl.textContent = counts[p];
    const cardEl = document.getElementById(`${p}Count`);
    if (cardEl) cardEl.textContent = counts[p];
  });

  buildHeroCountries();
  buildFooterFlags();

  rebuildSectorFilter('en');
  rebuildCountryFilter('en');

  const initial = getFiltered();
  renderCards(initial);
  updateFilterCount(initial);

  setTimeout(() => {
    initMap();
    updateMap(initial);
  }, 100);

  setTimeout(() => buildCharts(), 200);

  // Language buttons
  document.querySelectorAll('.lang-btn').forEach(btn => {
    btn.addEventListener('click', () => {
      document.querySelectorAll('.lang-btn').forEach(b => b.classList.remove('active'));
      btn.classList.add('active');
      applyLanguage(btn.dataset.lang);
    });
  });

  // Search
  const searchInput = document.getElementById('searchInput');
  if (searchInput) {
    searchInput.addEventListener('input', (e) => {
      filterSearch = e.target.value;
      const filtered = getFiltered();
      renderCards(filtered);
      updateMap(filtered);
      updateFilterCount(filtered);
    });
  }

  // Pillar filter (dropdown)
  const pillarSel = document.getElementById('pillarFilter');
  if (pillarSel) {
    pillarSel.addEventListener('change', (e) => {
      filterPillar = e.target.value;
      const filtered = getFiltered();
      renderCards(filtered);
      updateMap(filtered);
      updateFilterCount(filtered);
    });
  }

  // Sector filter
  const sectorSel = document.getElementById('sectorFilter');
  if (sectorSel) {
    sectorSel.addEventListener('change', (e) => {
      filterSector = e.target.value;
      const filtered = getFiltered();
      renderCards(filtered);
      updateMap(filtered);
      updateFilterCount(filtered);
    });
  }

  // Country filter
  const countrySel = document.getElementById('countryFilter');
  if (countrySel) {
    countrySel.addEventListener('change', (e) => {
      filterCountry = e.target.value;
      const filtered = getFiltered();
      renderCards(filtered);
      updateMap(filtered);
      updateFilterCount(filtered);
    });
  }

  // Sort
  const sortSel = document.getElementById('sortSelect');
  if (sortSel) {
    sortSel.addEventListener('change', (e) => {
      sortMode = e.target.value;
      const filtered = getFiltered();
      renderCards(filtered);
    });
  }

  // Reset
  const resetBtn = document.getElementById('resetBtn');
  if (resetBtn) {
    resetBtn.addEventListener('click', () => {
      filterSearch = '';
      filterPillar = '';
      filterSector = '';
      filterCountry = '';
      sortMode = 'az';
      if (searchInput) searchInput.value = '';
      if (pillarSel) pillarSel.value = '';
      if (sectorSel) sectorSel.value = '';
      if (countrySel) countrySel.value = '';
      if (sortSel) sortSel.value = 'az';
      // Reset map pills
      document.querySelectorAll('.map-pill').forEach(p => p.classList.remove('active'));
      const allPill = document.querySelector('.map-pill[data-filter="all"]');
      if (allPill) allPill.classList.add('active');
      const filtered = getFiltered();
      renderCards(filtered);
      updateMap(filtered);
      updateFilterCount(filtered);
    });
  }

  // Map pillar filter buttons
  document.querySelectorAll('.map-pill').forEach(btn => {
    btn.addEventListener('click', () => {
      document.querySelectorAll('.map-pill').forEach(b => b.classList.remove('active'));
      btn.classList.add('active');
      const f = btn.dataset.filter;
      filterPillar = f === 'all' ? '' : f;
      if (pillarSel) pillarSel.value = filterPillar;
      const filtered = getFiltered();
      renderCards(filtered);
      updateMap(filtered);
      updateFilterCount(filtered);
    });
  });

  // Pillar card browse buttons
  document.querySelectorAll('.pillar-browse-btn').forEach(btn => {
    btn.addEventListener('click', () => {
      const p = btn.dataset.pillarFilter;
      filterPillar = p;
      if (pillarSel) pillarSel.value = p;
      // Reset map pills
      document.querySelectorAll('.map-pill').forEach(b => b.classList.remove('active'));
      const matchPill = document.querySelector(`.map-pill[data-filter="${p}"]`);
      if (matchPill) matchPill.classList.add('active');
      const filtered = getFiltered();
      renderCards(filtered);
      updateMap(filtered);
      updateFilterCount(filtered);
      // Scroll to directory
      document.getElementById('directory').scrollIntoView({ behavior: 'smooth' });
    });
  });

  initNavScroll();
}

document.addEventListener('DOMContentLoaded', init);
